import os
import torch
from torchvision import models, transforms
from torch.utils.data import DataLoader, Dataset
from PIL import Image

# Function to download and load model checkpoint
def load_pretrained_model(model_name, url):
    model_path = f'{model_name}_checkpoint.pth'
    if not os.path.exists(model_path):
        os.system(f'wget -O {model_path} {url}')
    model = models.__dict__[model_name](pretrained=False)
    model.load_state_dict(torch.load(model_path))
    return model

# Custom Dataset class
class CustomDataset(Dataset):
    def __init__(self, image_paths, labels, transform=None):
        self.image_paths = image_paths
        self.labels = labels
        self.transform = transform

    def __len__(self):
        return len(self.image_paths)

    def __getitem__(self, idx):
        img_path = self.image_paths[idx]
        label = self.labels[idx]
        image = Image.open(img_path).convert('RGB')
        if self.transform:
            image = self.transform(image)
        return image, label

# Function to fine-tune the model
def fine_tune_model(model, train_loader, val_loader, num_epochs=10, learning_rate=0.001):
    device = torch.device('cuda' if torch.cuda.is_available() else 'cpu')
    model.to(device)
    
    criterion = torch.nn.CrossEntropyLoss()
    optimizer = torch.optim.Adam(model.parameters(), lr=learning_rate)

    for epoch in range(num_epochs):
        model.train()
        running_loss = 0.0
        for images, labels in train_loader:
            images, labels = images.to(device), labels.to(device)
            
            outputs = model(images)
            loss = criterion(outputs, labels)
            
            optimizer.zero_grad()
            loss.backward()
            optimizer.step()
            
            running_loss += loss.item()

        print(f'Epoch [{epoch+1}/{num_epochs}], Loss: {running_loss/len(train_loader):.4f}')

    # Evaluation
    model.eval()
    with torch.no_grad():
        correct = 0
        total = 0
        for images, labels in val_loader:
            images, labels = images.to(device), labels.to(device)
            outputs = model(images)
            _, predicted = torch.max(outputs.data, 1)
            total += labels.size(0)
            correct += (predicted == labels).sum().item()

    print(f'Validation Accuracy: {100 * correct / total:.2f}%')

# Example usage
if __name__ == "__main__":
    # Load pretrained model
    model = load_pretrained_model('resnet50', 'https://example.com/resnet50_checkpoint.pth')

    # Define transformations for the dataset
    transform = transforms.Compose([
        transforms.Resize((224, 224)),
        transforms.ToTensor(),
        transforms.Normalize(mean=[0.485, 0.456, 0.406], std=[0.229, 0.224, 0.225]),
    ])

    # Example paths and labels for the dataset
    train_image_paths = ['path/to/train/image1.jpg', 'path/to/train/image2.jpg']  # Add your image paths
    train_labels = [0, 1]  # Corresponding labels

    val_image_paths = ['path/to/val/image1.jpg', 'path/to/val/image2.jpg']  # Add your validation image paths
    val_labels = [0, 1]  # Corresponding validation labels

    # Create DataLoader for training and validation
    train_dataset = CustomDataset(train_image_paths, train_labels, transform=transform)
    val_dataset = CustomDataset(val_image_paths, val_labels, transform=transform)

    train_loader = DataLoader(train_dataset, batch_size=32, shuffle=True)
    val_loader = DataLoader(val_dataset, batch_size=32, shuffle=False)

    # Fine-tune the model
    fine_tune_model(model, train_loader, val_loader)